// Initialise the pagination loop.
// Resets the shared global staticData key used across Collect Page and Filter Stale Guests.
// NOTE: if a previous run was cancelled mid-pagination, this reset clears the partial
// accumulation cleanly before the new run starts.
const state = $getWorkflowStaticData('global');
state.guestGovernance_allGuests = [];
state.guestGovernance_done = false;

const firstUrl = 'https://graph.microsoft.com/beta/users' +
  '?$filter=userType eq \'Guest\'' +
  '&$select=id,displayName,mail,userPrincipalName,createdDateTime,signInActivity' +
  '&$top=999';

return [{ json: { nextUrl: firstUrl } }];

// Accumulate guests from this page into global staticData.
// Uses the 'global' scope so Init Pagination, Collect Page, and Filter Stale Guests
// all read and write the same object.
const state = $getWorkflowStaticData('global');
const page = $input.item.json;
const newGuests = page.value || [];

state.guestGovernance_allGuests = (state.guestGovernance_allGuests || []).concat(newGuests);
const nextLink = page['@odata.nextLink'] || null;
state.guestGovernance_done = !nextLink;

return [{
  json: {
    hasMore: !!nextLink,
    // Pass nextLink verbatim -- it is a fully-qualified URL from Graph and must not be
    // re-encoded. The HTTP Request node interpolates the expression value directly into
    // the URL field without additional encoding when used in an expression.
    nextUrl: nextLink,
    pageSize: newGuests.length,
    totalSoFar: state.guestGovernance_allGuests.length
  }
}];

// Read all accumulated guests from global staticData, apply stale filter,
// then clear the state. Clearing AFTER reading means a crash here loses the
// list for this run only -- the next run will re-fetch from Graph from scratch.
// This is an acceptable trade-off; see setup notes.
const state = $getWorkflowStaticData('global');
const guests = state.guestGovernance_allGuests || [];

// Clear now so the key does not grow indefinitely across runs
state.guestGovernance_allGuests = [];
state.guestGovernance_done = false;

const cutoffDate = new Date($('Set Config Parameters').item.json.cutoffDate);

const staleGuests = guests.filter(guest => {
  const signInActivity = guest.signInActivity;
  if (!signInActivity || !signInActivity.lastSignInDateTime) {
    const createdDate = new Date(guest.createdDateTime || '2000-01-01');
    return createdDate < cutoffDate;
  }
  return new Date(signInActivity.lastSignInDateTime) < cutoffDate;
});

// Emit exactly one summary item. Any Stale Guests? branches on hasStale.
// The true branch leads to Split Stale Guests which unpacks staleGuests into
// one item per guest for Loop Stale Guests.
return [{
  json: {
    staleCount: staleGuests.length,
    totalScanned: guests.length,
    hasStale: staleGuests.length > 0,
    staleGuests: staleGuests,
    cutoffDate: cutoffDate.toISOString()
  }
}];

// Unpack the staleGuests array from the summary item into one item per guest.
// This is what feeds SplitInBatches with a proper list.
const summary = $input.item.json;
const staleGuests = summary.staleGuests || [];

return staleGuests.map(guest => ({
  json: {
    staleCount: summary.staleCount,
    guestId: guest.id,
    guestEmail: guest.mail || guest.userPrincipalName,
    displayName: guest.displayName,
    lastSignIn: (
      guest.signInActivity && guest.signInActivity.lastSignInDateTime
        ? guest.signInActivity.lastSignInDateTime
        : 'Never'
    ),
    createdDateTime: guest.createdDateTime
  }
}));

